import "reflect-metadata";
import * as dotenv from "dotenv";
dotenv.config();
import { NestFactory } from "@nestjs/core";
import { AppModule } from "../src/app.module";
import { configureApp } from "../src/app-setup";
import { ExpressAdapter } from "@nestjs/platform-express";
import express from "express";

const server = express();

const promise = (async () => {
    const app = await NestFactory.create(AppModule, new ExpressAdapter(server), {
        logger: ["error", "warn", "log"],
    });
    configureApp(app);
    await app.init();
})();

export default async (req: any, res: any) => {
    try {
        await promise;
        server(req, res);
    } catch (error) {
        console.error("NestJS bootstrap failed:", error);
        res.status(500).json({ error: "Internal server error" });
    }
};

import { Injectable } from "@nestjs/common";
import { PrismaService } from "./prisma.service";
import { AvailabilitySlot } from "@bookinggg/core";

@Injectable()
export class AvailabilityService {
    constructor(private readonly prisma: PrismaService) { }

    async getAvailableSlots(
        tenantId: string,
        date: string,
        serviceId: string
    ): Promise<AvailabilitySlot[]> {
        const service = await (this.prisma as any).service.findUnique({
            where: { id: BigInt(serviceId) }
        });
        if (!service) throw new Error("Service not found");

        const settings = await (this.prisma as any).businessSettings.findFirst();
        if (!settings) throw new Error("Business settings not found");

        const openingHours = settings.openingHoursJson as any;

        // Use a fixed locale and timezone for deterministic weekday calculation
        const formatter = new Intl.DateTimeFormat("en-US", { weekday: "long", timeZone: "Europe/Bratislava" });
        const dayOfWeek = formatter.format(new Date(date)).toLowerCase();
        const dayHours = openingHours[dayOfWeek];

        if (!dayHours || dayHours.closed) return [];

        const existingBookings = await (this.prisma as any).booking.findMany({
            where: {
                startTime: {
                    gte: new Date(`${date}T00:00:00Z`),
                    lte: new Date(`${date}T23:59:59Z`)
                },
                status: { not: "cancelled" }
            }
        });

        const slots: AvailabilitySlot[] = [];
        const [startH, startM] = dayHours.open.split(":").map(Number);
        const [endH, endM] = dayHours.close.split(":").map(Number);

        let current = new Date(date);
        current.setUTCHours(startH, startM, 0, 0);

        const end = new Date(date);
        end.setUTCHours(endH, endM, 0, 0);

        while (current.getTime() + service.durationMin * 60000 <= end.getTime()) {
            const slotEnd = new Date(current.getTime() + service.durationMin * 60000);

            const isOverlap = existingBookings.some((b: any) => {
                const bStart = b.startTime.getTime();
                const bEnd = b.endTime.getTime();
                const sStart = current.getTime();
                const sEnd = slotEnd.getTime();
                return (sStart < bEnd && sEnd > bStart);
            });

            if (!isOverlap) {
                slots.push({
                    startAt: current.toISOString(),
                    endAt: slotEnd.toISOString(),
                    serviceId
                });
            }

            current = new Date(current.getTime() + 15 * 60000); // 15 min granularity
        }

        return slots;
    }

    async validateBooking(
        startTime: string,
        endTime: string,
        serviceId: string
    ): Promise<boolean> {
        const sStart = new Date(startTime).getTime();
        const sEnd = new Date(endTime).getTime();
        const actualDuration = (sEnd - sStart) / 60000;

        // 1. Service Check
        const service = await (this.prisma as any).service.findUnique({
            where: { id: BigInt(serviceId) }
        });
        if (!service || actualDuration !== service.durationMin) {
            return false;
        }

        // 2. Business Hours Check
        const settings = await (this.prisma as any).businessSettings.findFirst();
        if (settings) {
            const openingHours = settings.openingHoursJson as any;
            const formatter = new Intl.DateTimeFormat("en-US", { weekday: "long", timeZone: "Europe/Bratislava" });
            const dayOfWeek = formatter.format(new Date(startTime)).toLowerCase();
            const dayHours = openingHours[dayOfWeek];

            if (!dayHours || dayHours.closed) return false;

            const [startH, startM] = dayHours.open.split(":").map(Number);
            const [endH, endM] = dayHours.close.split(":").map(Number);

            const dayStart = new Date(startTime);
            dayStart.setUTCHours(startH, startM, 0, 0);
            const dayEnd = new Date(startTime);
            dayEnd.setUTCHours(endH, endM, 0, 0);

            if (sStart < dayStart.getTime() || sEnd > dayEnd.getTime()) {
                return false;
            }
        }

        // 3. Overlap Check
        const overlaps = await (this.prisma as any).booking.findMany({
            where: {
                AND: [
                    { startTime: { lt: new Date(endTime) } },
                    { endTime: { gt: new Date(startTime) } },
                    { status: { not: "cancelled" } }
                ]
            }
        });

        return overlaps.length === 0;
    }
}

import "reflect-metadata";
import * as dotenv from "dotenv";
dotenv.config();

import { NestFactory } from "@nestjs/core";
import { AppModule } from "./app.module";
import { configureApp } from "./app-setup";
import { IncomingMessage, ServerResponse } from "http";

let app: any;

async function getApp() {
  if (!app) {
    app = await NestFactory.create(AppModule, {
      logger: ["error", "warn"]
    });
    configureApp(app);
    await app.init();
  }
  return app;
}

export default async function handler(
  req: IncomingMessage,
  res: ServerResponse
) {
  const nestApp = await getApp();
  const expressInstance = nestApp.getHttpAdapter().getInstance();
  expressInstance(req, res);
}

import { Controller, Get, Post, Body, Param, Put, Delete, UseGuards } from "@nestjs/common";
import { PrismaService } from "./prisma.service";
import { ApiKeyGuard } from "./api-key.guard";

@Controller("api/tenants/:tenantId/services")
@UseGuards(ApiKeyGuard)
export class ServicesController {
    constructor(private readonly prisma: PrismaService) { }

    @Get()
    async listServices(@Param("tenantId") tenantId: string) {
        return (this.prisma as any).service.findMany({
            orderBy: { createdAt: "desc" }
        });
    }

    @Post()
    async createService(
        @Param("tenantId") tenantId: string,
        @Body() data: any
    ) {
        return (this.prisma as any).service.create({
            data: {
                ...data,
                price: Number(data.price),
                durationMin: Number(data.durationMin),
                isActive: data.isActive ?? true
            }
        });
    }

    @Put(":id")
    async updateService(
        @Param("tenantId") tenantId: string,
        @Param("id") id: string,
        @Body() data: any
    ) {
        return (this.prisma as any).service.update({
            where: { id: BigInt(id) },
            data: {
                ...data,
                price: data.price !== undefined ? Number(data.price) : undefined,
                durationMin: data.durationMin !== undefined ? Number(data.durationMin) : undefined
            }
        });
    }

    @Delete(":id")
    async deleteService(
        @Param("tenantId") tenantId: string,
        @Param("id") id: string
    ) {
        return (this.prisma as any).service.delete({
            where: { id: BigInt(id) }
        });
    }
}

import { UnauthorizedException } from "@nestjs/common";
import { AuthService } from "../src/auth/auth.service";

describe("AuthService", () => {
  const prisma = {
    user: {
      findUnique: jest.fn(),
      create: jest.fn(),
      update: jest.fn()
    },
    oauthAccount: {
      findUnique: jest.fn(),
      create: jest.fn()
    },
    refreshToken: {
      create: jest.fn(),
      findUnique: jest.fn(),
      update: jest.fn(),
      updateMany: jest.fn()
    },
    session: {
      create: jest.fn(),
      findMany: jest.fn()
    },
    tokenBlacklist: {
      findUnique: jest.fn(),
      create: jest.fn()
    }
  } as any;

  const jwtService = {
    signAsync: jest.fn().mockResolvedValue("access-token"),
    verifyAsync: jest.fn().mockResolvedValue({ sub: "user_1", email: "a@b.com" }),
    decode: jest.fn().mockReturnValue({ exp: Math.floor(Date.now() / 1000) + 600 })
  } as any;

  const service = new AuthService(prisma, jwtService);

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it("refresh rejects expired tokens", async () => {
    prisma.refreshToken.findUnique.mockResolvedValue({
      token: "hashed",
      isRevoked: false,
      expiresAt: new Date(Date.now() - 1000),
      user: { id: "u1", email: "e@e.com" }
    });

    await expect(service.refresh("rt", "127.0.0.1")).rejects.toBeInstanceOf(
      UnauthorizedException
    );
  });

  it("biometric setup keeps password fallback", async () => {
    prisma.user.findUnique.mockResolvedValue({ id: "u1" });
    prisma.user.update.mockResolvedValue({ id: "u1", biometricId: "cred" });

    const result = await service.biometric({ userId: "u1", credentialId: "cred" });
    expect(result.fallback).toBe("password");
  });
  it("mocks oauth providers", async () => {
    prisma.oauthAccount.findUnique.mockResolvedValue(null);
    prisma.user.findUnique.mockResolvedValue({ id: "u1", email: "google.demo@booking.local" });
    prisma.oauthAccount.create.mockResolvedValue({
      user: { id: "u1", email: "google.demo@booking.local" }
    });
    prisma.refreshToken.create.mockResolvedValue({});
    prisma.session.create.mockResolvedValue({});

    const result = await service.loginWithOAuth(
      { provider: "google", providerAccountId: "pid", email: "google.demo@booking.local" },
      "127.0.0.1"
    );

    expect(result.accessToken).toBe("access-token");
  });

});

